// Demonstrates local draft state (draft.patch), a system notify (notify.show),
// and navigation back to the catalog (nav.back) — the three action kinds a
// plugin can emit without any host domain reducer.
defineRuntimeBundle(({ ui }) => {
  return {
    id: 'counter',
    title: 'Counter',
    packageIds: ['ui'],
    initialSurfaceState: {
      main: { count: 0 },
    },
    surfaces: {
      main: {
        packId: 'ui.card.v1',
        render({ state }) {
          const count = Number(state?.draft?.count ?? 0);
          return ui.panel([
            ui.text('Count: ' + count),
            ui.row([
              ui.button('-', { onClick: { handler: 'dec' } }),
              ui.button('+', { onClick: { handler: 'inc' } }),
            ]),
            ui.button('Reset', { onClick: { handler: 'reset' } }),
            ui.button('Done', { onClick: { handler: 'done' } }),
          ]);
        },
        handlers: {
          inc({ state, dispatch }) {
            dispatch({ type: 'draft.set', payload: { path: 'count', value: Number(state?.draft?.count ?? 0) + 1 } });
          },
          dec({ state, dispatch }) {
            dispatch({ type: 'draft.set', payload: { path: 'count', value: Number(state?.draft?.count ?? 0) - 1 } });
          },
          reset({ dispatch }) {
            dispatch({ type: 'draft.reset' });
            dispatch({ type: 'notify.show', payload: { message: 'Counter reset' } });
          },
          done({ state, dispatch }) {
            dispatch({ type: 'notify.show', payload: { message: 'Final count: ' + (state?.draft?.count ?? 0) } });
            dispatch({ type: 'nav.back' });
          },
        },
      },
    },
  };
});
`,bg=`// Stateful feed middleware plugin: keyword filtering lives in pluginState, not in the feed reducer.
defineRuntimeBundle(({ ui }) => ({
  id: 'feed-keyword-lens',
  title: 'Keyword Lens',
  packageIds: ['ui'],
  initialPluginState: { query: '', matchCount: 0 },
  surfaces: {
    panel: {
      packId: 'ui.card.v1',
      render({ state }) {
        const plugin = state.plugin || {};
        return ui.panel([
          ui.text('Filter posts by author or text'),
          ui.input(plugin.query || '', { placeholder: 'quickjs, alice, spam…', onChange: { handler: 'setQuery' } }),
          ui.row([ui.badge('matches: ' + String(plugin.matchCount || 0)), ui.button('Clear', { onClick: { handler: 'clear' } })]),
        ]);
      },
      handlers: {
        setQuery({ dispatchPluginAction }, args) {
          dispatchPluginAction('state.merge', { query: String((args && args.value) || '') });
        },
        clear({ dispatchPluginAction }) {
          dispatchPluginAction('state.merge', { query: '' });
        },
      },
    },
  },
  feed: {
    apply({ posts, pluginState }) {
      const query = String(pluginState.query || '').trim().toLowerCase();
      const next = query
        ? posts.filter((post) => post.author.toLowerCase().includes(query) || post.text.toLowerCase().includes(query))
        : posts;
      const annotations = Object.fromEntries(next.map((post) => [post.id, query ? { keywordMatch: true } : {}]));
      return { posts: next, annotations, statePatch: { matchCount: next.length }, debug: { query } };
    },
  },
}));
`,Bg=`// Stateful feed middleware plugin: manually mute authors; muted authors disappear from the derived visible feed.
defineRuntimeBundle(({ ui }) => ({
  id: 'feed-author-mute',
  title: 'Author Mute',
  packageIds: ['ui'],
  initialPluginState: { mutedAuthors: [] },
  surfaces: {
    panel: {
      packId: 'ui.card.v1',
      render({ state }) {
        const plugin = state.plugin || {};
        const muted = Array.isArray(plugin.mutedAuthors) ? plugin.mutedAuthors : [];
        const posts = (state.feed && Array.isArray(state.feed.posts)) ? state.feed.posts : [];
        const authors = [];
        posts.forEach((post) => { if (authors.indexOf(post.author) < 0) authors.push(post.author); });
        return ui.panel([
          ui.text('Hide all posts from selected authors.'),
          ui.badge('muted: ' + String(muted.length)),
          ui.row(authors.map((author) => ui.button((muted.indexOf(author) >= 0 ? 'Unmute ' : 'Mute ') + author, { onClick: { handler: 'toggle', args: { author } } }))),
          muted.length ? ui.button('Clear muted authors', { onClick: { handler: 'clear' } }) : ui.text('No muted authors.'),
        ]);
      },
      handlers: {
        toggle({ pluginState, dispatchPluginAction }, args) {
          const author = String(args && args.author || '');
          const current = Array.isArray(pluginState.mutedAuthors) ? pluginState.mutedAuthors : [];
          const next = current.indexOf(author) >= 0 ? current.filter((x) => x !== author) : current.concat(author);
          dispatchPluginAction('state.merge', { mutedAuthors: next });
        },
        clear({ dispatchPluginAction }) {
          dispatchPluginAction('state.merge', { mutedAuthors: [] });
        },
      },
    },
  },
  feed: {
    apply({ posts, pluginState }) {
      const muted = Array.isArray(pluginState.mutedAuthors) ? pluginState.mutedAuthors : [];
      const mutedSet = new Set(muted);
      return {
        posts: posts.filter((post) => !mutedSet.has(post.author)),
        hiddenPostIds: posts.filter((post) => mutedSet.has(post.author)).map((post) => post.id),
        debug: { mutedAuthors: muted },
      };
    },
  },
}));
`,Ug=`// Stateful feed middleware plugin: show only recent posts.
defineRuntimeBundle(({ ui }) => ({
  id: 'feed-freshness-window',
  title: 'Freshness Window',
  packageIds: ['ui'],
  initialPluginState: { minutes: 240 },
  surfaces: {
    panel: {
      packId: 'ui.card.v1',
      render({ state }) {
        const plugin = state.plugin || {};
        const minutes = Number(plugin.minutes || 240);
        return ui.panel([
          ui.text('Hide posts older than the selected window.'),
          ui.badge(minutes >= 999999 ? 'window: all' : 'window: ' + String(minutes) + 'm'),
          ui.row([
            ui.button('15m', { onClick: { handler: 'set', args: { minutes: 15 } } }),
            ui.button('1h', { onClick: { handler: 'set', args: { minutes: 60 } } }),
            ui.button('4h', { onClick: { handler: 'set', args: { minutes: 240 } } }),
            ui.button('All', { onClick: { handler: 'set', args: { minutes: 999999 } } }),
          ]),
        ]);
      },
      handlers: {
        set({ dispatchPluginAction }, args) {
          dispatchPluginAction('state.merge', { minutes: Number(args && args.minutes || 240) });
        },
      },
    },
  },
  feed: {
    apply({ posts, pluginState, context }) {
      const minutes = Number(pluginState.minutes || 240);
      const cutoff = context.now - minutes * 60 * 1000;
      const next = minutes >= 999999 ? posts : posts.filter((post) => post.ts >= cutoff);
      return { posts: next, debug: { minutes, cutoff } };
    },
  },
}));
`,Vg=`// Stateful incoming-message + middleware plugin: tags new messages and can filter by topic.
defineRuntimeBundle(({ ui }) => ({
  id: 'feed-topic-tagger',
  title: 'Topic Tagger',
  packageIds: ['ui'],
  initialPluginState: { topic: 'all', counts: {} },
  surfaces: {
    panel: {
      packId: 'ui.card.v1',
      render({ state }) {
        const plugin = state.plugin || {};
        const topic = String(plugin.topic || 'all');
        const counts = plugin.counts || {};
        return ui.panel([
          ui.text('Tags incoming messages; optionally show one topic.'),
          ui.row(['all', 'vm', 'frontend', 'security', 'spam'].map((name) => ui.button((topic === name ? '• ' : '') + name, { onClick: { handler: 'topic', args: { topic: name } } }))),
          ui.table(Object.entries(counts).map(([name, count]) => [name, String(count)]), { headers: ['Topic', 'Seen'] }),
        ]);
      },
      handlers: {
        topic({ dispatchPluginAction }, args) {
          dispatchPluginAction('state.merge', { topic: String(args && args.topic || 'all') });
        },
      },
    },
  },
  feed: {
    onIncomingMessage({ message, pluginState }) {
      const text = String(message.text || '').toLowerCase();
      const tags = [];
      if (text.includes('quickjs') || text.includes('vm') || text.includes('sandbox')) tags.push('vm');
      if (text.includes('react') || text.includes('css') || text.includes('frontend')) tags.push('frontend');
      if (text.includes('dom') || text.includes('capability') || text.includes('safe')) tags.push('security');
      if (text.includes('crypto') || text.includes('free money')) tags.push('spam');
      const nextTags = Array.from(new Set([...(Array.isArray(message.tags) ? message.tags : []), ...tags]));
      const counts = { ...(pluginState.counts || {}) };
      nextTags.forEach((tag) => { counts[tag] = Number(counts[tag] || 0) + 1; });
      return { message: { ...message, tags: nextTags }, statePatch: { counts } };
    },
    apply({ posts, pluginState }) {
      const topic = String(pluginState.topic || 'all');
      const next = topic === 'all' ? posts : posts.filter((post) => Array.isArray(post.tags) && post.tags.indexOf(topic) >= 0);
      return {
        posts: next,
        annotations: Object.fromEntries(next.map((post) => [post.id, { tags: Array.isArray(post.tags) ? post.tags : [] }])),
        debug: { topic },
      };
    },
  },
}));
